INSERT INTO t_p67171637_yug_transfer_prize_l.bot_daily_posts (photo_url, greeting, description) VALUES
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/b7831f38-fd8d-41c5-82b3-2f9970e82d84.jpg', '🚕 Доброе утро! Куда поедем сегодня?', 'Закажите трансфер заранее — мы приедем точно вовремя.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/b2676df6-3e09-45b9-a7c0-db07d432a208.jpg', '🚕 Отдых на побережье? Довезём с комфортом!', 'Кондиционер, удобные сиденья, приятная музыка — всё для вас.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/a12a889b-c69a-4a0f-bc36-0552a7101932.jpg', '🚕 Межгород? Легко! ЮГ ТРАНСФЕР доставит куда нужно.', 'Поездки между городами юга России по фиксированной цене.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/3137d3f3-a238-45ef-b6cf-a39b04cabde7.jpg', '🚕 Горные дороги — наша стихия!', 'Опытные водители знают каждый поворот. Безопасность гарантирована.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/24e2c44e-cf9e-4416-a902-0367e729410e.jpg', '🚕 Встретим на вокзале — довезём до места!', 'Водитель с табличкой уже ждёт вас на выходе.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/810b2391-34e0-4825-9145-1960ea8ff90a.jpg', '🚕 Красивые маршруты юга — путешествуйте с нами!', 'Не просто поездка, а настоящее удовольствие от дороги.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/d072b1a1-ae08-4dc2-bf56-812b1c82f280.jpg', '🚕 Трансфер из аэропорта — без ожидания и переплат!', 'Отслеживаем ваш рейс. Задержка? Мы подождём бесплатно.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/f4fe5850-84eb-4739-90f4-f9a0e4b0f91c.jpg', '🚕 Дорога вдоль моря — лучший способ начать отпуск!', 'Закажите такси онлайн за пару кликов.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/65d194bc-fe33-4de1-8b7f-cc5744f55f20.jpg', '🚕 VIP-трансфер для особых случаев.', 'Бизнес-класс, представительские авто. Встречи, свадьбы, мероприятия.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/139ada61-318b-4d96-9e4b-beb6504eeab1.jpg', '🚕 Семейный отдых начинается с удобной поездки!', 'Просторные авто на 5-7 мест. Детские кресла бесплатно.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/09e7d402-9bb1-40dd-b611-a1d8644cc321.jpg', '🚕 Сочи, Адлер, Красная Поляна — поехали!', 'Знаем все маршруты олимпийского побережья.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/4916697c-fd0f-4741-af49-0bb74b3fc139.jpg', '🚕 Осень — время путешествовать по югу!', 'Мягкий климат, красивые пейзажи. А мы — ваш транспорт.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/d8b22c2e-31ad-49e5-b11e-7220b60940fc.jpg', '🚕 Ночные поездки? Без проблем — работаем 24/7!', 'Поздний рейс или ранний выезд — мы всегда на связи.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/30c4ec43-2f16-46aa-841c-207c1beab6c4.jpg', '🚕 Эльбрус, Домбай, Архыз — трансфер в горы!', 'Довезём к подножию гор с комфортом и в лучшем настроении.'),
('https://cdn.poehali.dev/projects/c2bd1535-aa26-4a07-a3f6-51d547fc1da3/files/49f83571-4b99-4521-a003-011ebba09d53.jpg', '🚕 Романтическое путешествие? Мы знаем лучшие маршруты!', 'Панорамные точки, закаты, виноградники — создайте незабываемый день.');